import React, { useState } from 'react';
import './GalleryPage.css';
import { PageHero, Reveal, SiteFooter } from '../../ui/Shared';

const ITEMS = [
  { wide: true, num: '01', label: 'Title Fight — Newark, NJ · June 1, 2024', content: <div style={{ fontFamily: "'Cinzel Decorative',serif", fontSize: '2rem', color: 'rgba(139,0,0,0.35)', letterSpacing: '0.1em' }}>UFC 302</div> },
  { num: '02', label: 'UFC 300 — Walkout', content: <svg width="36" height="36" viewBox="0 0 50 50" fill="none" style={{ opacity: 0.25 }}><rect x="23" y="2" width="4" height="46" fill="#8b0000"/><rect x="2" y="23" width="46" height="4" fill="#8b0000"/><circle cx="25" cy="25" r="10" fill="none" stroke="#c0392b" strokeWidth="1.5"/></svg> },
  { num: '03', label: 'Joel Alvarez Finish · R1', content: <div style={{ fontFamily: "'Cinzel Decorative',serif", fontSize: '3rem', color: 'rgba(139,0,0,0.2)' }}>KO</div> },
  { num: '04', label: 'Homeland · Armenia', content: <div style={{ display:'flex', flexDirection:'column', width:55, borderRadius:2, overflow:'hidden' }}><div style={{ height:13, background:'#D90012' }}/><div style={{ height:13, background:'#0033A0' }}/><div style={{ height:13, background:'#F2A800' }}/></div> },
  { num: '05', label: 'The Octagon', content: <svg width="44" height="44" viewBox="0 0 100 100" fill="none" style={{ opacity: 0.2 }}><circle cx="50" cy="50" r="44" fill="none" stroke="#8b0000" strokeWidth="1"/><path d="M50 6 L94 28 L94 72 L50 94 L6 72 L6 28 Z" fill="none" stroke="#8b0000" strokeWidth=".8" opacity=".5"/></svg> },
  { num: '06', label: 'Training · Grappling', content: <div style={{ fontFamily: "'Cinzel Decorative',serif", fontSize: '1.3rem', color: 'rgba(139,0,0,0.25)' }}>SAMBO</div> },
  { num: '07', label: 'Press Conference', content: null },
  { num: '08', label: 'Hand Raised · Victory', content: <div style={{ fontFamily: "'Cinzel Decorative',serif", fontSize: '2rem', color: 'rgba(139,0,0,0.2)' }}>W</div> },
  { num: '09', label: 'Akhalkalaki — Hometown', content: null },
];

const CATS = ['All', 'Fight Night', 'Training', 'Armenia'];

export default function GalleryPage() {
  const [cat, setCat] = useState('All');
  return (
    <>
      <PageHero eyebrow="Images & Visuals" title="The" accent="Gallery" />
      <div className="section-wrap">
        <Reveal>
          <div className="gallery-cats">
            {CATS.map(c => (
              <div key={c} className={`gallery-cat${cat === c ? ' active' : ''}`} onClick={() => setCat(c)}>{c}</div>
            ))}
          </div>
        </Reveal>
        <Reveal>
          <div className="gallery-grid">
            {ITEMS.map(g => (
              <div key={g.num} className={`gallery-item${g.wide ? ' wide' : ''}`}>
                <div className="gal-inner">
                  {g.content}
                  <div className="gal-label">{g.label}</div>
                </div>
                <div className="gal-ov"><span>View Photo</span></div>
                <div className="gal-num">{g.num}</div>
              </div>
            ))}
          </div>
        </Reveal>
      </div>
      <SiteFooter sub="The Armenian · Gallery" />
    </>
  );
}
